	if err != nil {
		// `git ls-remote --exit-code` exits with 2 when no refs matched.
		if exitErr := (&exec.ExitError{}); errors.As(err, &exitErr) && exitErr.ExitCode() == 2 {
			return "", fmt.Errorf("%w: %q on %q", ErrRefNotFound, ref, rawURL)
		}
