func TestHasCommit_Present(t *testing.T) {
	requireGit(t)
	withDetectReset(t)

	r := makeRepo(t)
	dst := filepath.Join(t.TempDir(), "out")
	if err := Clone(testCtx(t), r.Path, dst); err != nil {
