	}
	repo, err := Open(dst)
	if err != nil {
		t.Fatalf("Open: %v", err)
	}
	defer func() { _ = repo.Close() }()

	absent := "0000000000000000000000000000000000000000"
	has, err := repo.HasCommit(absent)
	if err != nil {
		t.Fatalf("HasCommit absent: %v", err)
	}
	if has {
		t.Fatalf("expected HasCommit(%s) = false", absent)
