	mustGit(t, dir, "config", "user.email", "test@aienvs.invalid")
	mustGit(t, dir, "config", "user.name", "aienvs-test")
	// Ensure the post-init working tree is clean of `init.defaultBranch`
	// warnings so CombinedOutput stays quiet.
