16	// ErrBlobNotFound is returned when a requested path does not resolve to
17	// a blob at the given SHA. A present-but-non-blob entry (tree,
18	// submodule, symlink with no target blob) produces the same sentinel:
19	// callers treat the path as missing.
20	var ErrBlobNotFound = errors.New("git: blob not found")
21	
22	// ErrShaNotInCache is returned when a commit SHA is not present in the
23	// local cache. Materialize is responsible for populating the cache;
24	// this sentinel surfaces to help tests and higher layers distinguish
25	// "cache miss" from a genuine read error.
26	var ErrShaNotInCache = errors.New("git: sha not in cache")
27	
28	// TreeEntry names a single blob reachable from a commit tree.
29	//
30	// Path is the POSIX-style forward-slash path from the tree root.
31	// Mode mirrors the git file mode (`100644`, `100755`, `120000` for a
32	// symlink). Size is the blob's uncompressed size.
33	//
34	// Symlinks are returned with Mode == 0o120000 and the blob content is
35	// the link target. Callers upstream decide whether to follow them;
36	// aienvs's IR decoder treats symlinks as opaque blobs.
37	type TreeEntry struct {
38		Path string
39		Mode uint32
40		Size int64
41		Hash string
42	}
