44	// Repository wraps a materialized bare clone so the rest of aienvs can
45	// read trees and blobs without importing go-git directly.
46	//
47	// Instances are cheap to construct but hold an open object store, so
48	// callers should Close them when done. Repository methods are safe for
49	// concurrent read-only use.
50	type Repository struct {
51		path string
52		repo *gogit.Repository
53	}
54	
55	// Open attaches to the bare clone at repoPath. The directory must already
56	// have been populated by Materialize; Open does not clone.
57	func Open(repoPath string) (*Repository, error) {
58		r, err := gogit.PlainOpen(repoPath)
59		if err != nil {
60			return nil, fmt.Errorf("git: open %q: %w", repoPath, err)
61		}
62		return &Repository{path: repoPath, repo: r}, nil
63	}
64	
65	// Close releases the underlying object store handles. Safe to call
66	// multiple times.
67	func (r *Repository) Close() error {
68		// go-git 5.17 PlainOpen returns an in-memory wrapper with no explicit
69		// close; nothing to release today. The method exists so a future
70		// go-git version that grows a Close() can be wired in without a
71		// caller-visible break.
72		return nil
73	}
74	
75	// Path returns the filesystem path the repository was opened at.
76	func (r *Repository) Path() string {
77		return r.path
78	}
