80	// HasCommit reports whether the given 40-char SHA resolves to a commit
81	// object in the local store. It returns [ErrShaNotInCache] as a clean
82	// sentinel for callers that need to branch on cache-miss.
83	func (r *Repository) HasCommit(sha string) (bool, error) {
84		if !shaPattern.MatchString(strings.ToLower(sha)) {
85			return false, fmt.Errorf("git: has-commit: invalid sha %q", sha)
86		}
87		hash := plumbing.NewHash(sha)
88		_, err := r.repo.CommitObject(hash)
89		if err == nil {
90			return true, nil
91		}
92		if errors.Is(err, plumbing.ErrObjectNotFound) {
93			return false, nil
94		}
95		return false, fmt.Errorf("git: has-commit %s: %w", sha, err)
96	}
