98	// ReadTree walks the tree reachable from commitSHA and returns every
99	// blob entry under it, keyed by POSIX path. Sub-trees are expanded
100	// recursively; submodule gitlinks are skipped (they are not part of the
101	// canonical source tree from aienvs's perspective).
102	//
103	// Deterministic order: entries are sorted by Path so callers consuming
104	// the slice for diffing or hashing get stable results across runs.
105	func (r *Repository) ReadTree(commitSHA string) ([]TreeEntry, error) {
106		sha := strings.ToLower(strings.TrimSpace(commitSHA))
107		if !shaPattern.MatchString(sha) {
108			return nil, fmt.Errorf("git: read-tree: invalid sha %q", commitSHA)
109		}
110		commit, err := r.repo.CommitObject(plumbing.NewHash(sha))
111		if err != nil {
112			if errors.Is(err, plumbing.ErrObjectNotFound) {
113				return nil, fmt.Errorf("%w: %s", ErrShaNotInCache, sha)
114			}
115			return nil, fmt.Errorf("git: read-tree: commit %s: %w", sha, err)
116		}
117		tree, err := commit.Tree()
118		if err != nil {
119			return nil, fmt.Errorf("git: read-tree: tree %s: %w", sha, err)
120		}
121	
122		entries := make([]TreeEntry, 0, 64)
123		walker := object.NewTreeWalker(tree, true, nil)
124		defer walker.Close()
125		for {
126			name, entry, err := walker.Next()
127			if err != nil {
128				if errors.Is(err, io.EOF) {
129					break
130				}
131				return nil, fmt.Errorf("git: read-tree: walk: %w", err)
132			}
133			// Skip directories (we only report blobs) and submodule gitlinks.
134			if !entry.Mode.IsFile() && entry.Mode != 0o120000 {
135				continue
136			}
137			blob, err := r.repo.BlobObject(entry.Hash)
138			if err != nil {
139				return nil, fmt.Errorf("git: read-tree: blob %s at %s: %w", entry.Hash, name, err)
140			}
141			entries = append(entries, TreeEntry{
142				Path: path.Clean(name),
143				Mode: uint32(entry.Mode),
144				Size: blob.Size,
145				Hash: entry.Hash.String(),
146			})
147		}
148		sortEntries(entries)
149		return entries, nil
150	}
