152	// BlobContent returns the bytes of the blob at relPath in the tree of
153	// commitSHA. Missing paths, directories, and submodule gitlinks all
154	// surface as [ErrBlobNotFound].
155	//
156	// The caller is responsible for any size limits; BlobContent loads the
157	// full blob into memory. The IR decoder in unit 7 will wrap this with
158	// per-concept caps.
159	func (r *Repository) BlobContent(commitSHA, relPath string) ([]byte, error) {
160		sha := strings.ToLower(strings.TrimSpace(commitSHA))
161		if !shaPattern.MatchString(sha) {
162			return nil, fmt.Errorf("git: blob: invalid sha %q", commitSHA)
163		}
164		clean := path.Clean("/" + relPath)
165		if clean == "/" {
166			return nil, fmt.Errorf("%w: empty path", ErrBlobNotFound)
167		}
168		clean = strings.TrimPrefix(clean, "/")
169	
170		commit, err := r.repo.CommitObject(plumbing.NewHash(sha))
171		if err != nil {
172			if errors.Is(err, plumbing.ErrObjectNotFound) {
173				return nil, fmt.Errorf("%w: %s", ErrShaNotInCache, sha)
174			}
175			return nil, fmt.Errorf("git: blob: commit %s: %w", sha, err)
176		}
177		tree, err := commit.Tree()
178		if err != nil {
179			return nil, fmt.Errorf("git: blob: tree %s: %w", sha, err)
180		}
181		file, err := tree.File(clean)
182		if err != nil {
183			if errors.Is(err, object.ErrFileNotFound) {
184				return nil, fmt.Errorf("%w: %s at %s", ErrBlobNotFound, clean, sha)
185			}
186			return nil, fmt.Errorf("git: blob: file %q at %s: %w", clean, sha, err)
187		}
188		rc, err := file.Reader()
189		if err != nil {
190			return nil, fmt.Errorf("git: blob: reader %q at %s: %w", clean, sha, err)
191		}
192		defer func() { _ = rc.Close() }()
193		buf, err := io.ReadAll(rc)
194		if err != nil {
195			return nil, fmt.Errorf("git: blob: read %q at %s: %w", clean, sha, err)
196		}
197		return buf, nil
198	}
