200	// sortEntries sorts TreeEntries by Path in ascending lexicographic order.
201	// The ordering is part of ReadTree's public contract.
202	func sortEntries(entries []TreeEntry) {
203		slices.SortFunc(entries, func(a, b TreeEntry) int {
204			return strings.Compare(a.Path, b.Path)
205		})
206	}
